-- فحص هيكل جدول المجموعات
DESC groups;

-- عرض جميع المجموعات المحفوظة
SELECT id, code, name, dailyWage, workMinutes, latePenaltyRate, earlyLeavePenaltyRate, shiftStartTime, shiftEndTime, isActive, createdAt, updatedAt 
FROM groups 
LIMIT 10;

-- عدد المجموعات الكلي
SELECT COUNT(*) as total_groups FROM groups;

